def test_duplicate_account_number_returns_409(auth_headers, api_client, unique_account):
    payload = {
        "account_number": unique_account,
        "account_name": "Carol Conflict",
        "bank_code": "003"
    }

    first_key = <generate_uuid>("test_409_first")
    first = api_client.post(
        "/beneficiaries",
        json=payload,
        headers={**auth_headers, "Idempotency-Key": first_key}
    )
    assert first.status_code == 201

    second_key = <generate_uuid>("test_409_second")
    second = api_client.post(
        "/beneficiaries",
        json=payload,
        headers={**auth_headers, "Idempotency-Key": second_key}
    )
    assert second.status_code == 409
    error_body = second.json()
    assert error_body.get("error_code") == "DUPLICATE_ACCOUNT"
